import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is the formula for density?", a: "Density = Mass  x  Volume ( = m/V). The standard SI unit is kg/m- Common units include g/cm- and g/mL. You can rearrange this to find mass (m =   x  V) or volume (V = m/)." },
  { q: "What is the density of water?", a: "The density of water is approximately 1 g/cm- (or 1000 kg/m- at 4- Objects less dense than water float; objects more dense sink. This is the basis of buoyancy." },
  { q: "What is the density of air?", a: "The density of dry air at sea level at 15- is approximately 1.225 kg/m- Air density decreases with altitude and increases with higher pressure." },
  { q: "Why does density matter?", a: "Density determines whether objects float or sink, affects material strength, is used in chemistry to identify substances, and is critical in engineering, aviation, and fluid mechanics." },
  { q: "What is relative density (specific gravity)?", a: "Relative density (or specific gravity) is the ratio of a substance's density to the density of a reference substance (usually water at 4- A specific gravity above 1 means the substance is denser than water and will sink." },
  { q: "How does temperature affect density?", a: "For most liquids and solids, density decreases as temperature increases (thermal expansion). Water is an exception - it is densest at 4- and becomes less dense both above and below this temperature. This is why ice floats." },
  { q: "What is the densest naturally occurring element?", a: "Osmium (Os) is the densest naturally occurring element, with a density of approximately 22.59 g/cm- Iridium is a close second at 22.56 g/cm- Both are rare platinum-group metals." },
];

type SolveFor = "density" | "mass" | "volume";

export default function DensityCalculator() {
  const [solveFor, setSolveFor] = useState<SolveFor>("density");
  const [mass, setMass] = useState(500);
  const [volume, setVolume] = useState(250);
  const [density, setDensity] = useState(2);

  const result = solveFor === "density" ? mass / volume
    : solveFor === "mass" ? density * volume
    : mass / density;
  const resultLabel = solveFor === "density" ? "g/cm3" : solveFor === "mass" ? "grams" : "cm3";

  return (
    <>
      <SEOHead
        title="Free Density Calculator Online - Calculate Density Mass or Volume Instantly | CalcHive"
        description="Free online density calculator. Calculate density, mass or volume using the physics formula Density = Mass divided by Volume instantly. 100% free for students and professionals, no signup required."
        canonical="/density-calculator"
        keywords="free density calculator, density mass volume calculator free online, physics density formula calculator free, calculate density free, density calculator for students free"
        category="Science Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-cyan-600 dark:text-cyan-400 bg-cyan-50 dark:bg-cyan-950/50 px-3 py-1 rounded-full mb-4 inline-block">Measurement</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Density Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free density calculator to calculate density free, mass, or volume using the physics formula. This density mass volume calculator free online also works as a physics density formula calculator free and density calculator for students free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <div className="flex gap-2 mb-6">
          {(["density", "mass", "volume"] as SolveFor[]).map(v => (
            <button key={v} onClick={() => setSolveFor(v)} className={`flex-1 py-2 rounded-xl text-sm font-semibold border capitalize transition-all ${solveFor === v ? "bg-cyan-600 text-white border-cyan-600" : "bg-card text-muted-foreground border-border hover:border-cyan-400"}`}>Solve for {v}</button>
          ))}
        </div>
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            {solveFor !== "mass" && <SliderInput id="mass" label="Mass (grams)" value={mass} min={0.1} max={10000} step={0.1} onChange={setMass} format={v => `${v} g`} testId="input-mass" />}
            {solveFor !== "volume" && <SliderInput id="volume" label="Volume (cm3)" value={volume} min={0.1} max={10000} step={0.1} onChange={setVolume} format={v => `${v} cm3`} testId="input-volume" />}
            {solveFor !== "density" && <SliderInput id="density" label="Density (g/cm3)" value={density} min={0.01} max={22} step={0.01} onChange={setDensity} format={v => `${v.toFixed(2)} g/cm3`} testId="input-density" />}
          </div>
          <motion.div key={`${solveFor}-${result}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-cyan-500 to-cyan-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{solveFor.charAt(0).toUpperCase() + solveFor.slice(1)}</p>
              <p className="text-5xl font-black text-white tracking-tight" data-testid="result-value">{isFinite(result) ? result.toFixed(4) : "-"} {resultLabel}</p>
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Density Mass and Volume for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Density is an intrinsic property of matter - it doesn't change with the amount of substance, only with temperature and pressure. The same formula can be rearranged to solve for mass or volume when density is known.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-2">
            <p>Density (D) = Mass (m) / Volume (V) - g/cm3 or kg/m3</p>
            <p>Mass (m) = Density (D) x Volume (V) - grams or kg</p>
            <p>Volume (V) = Mass (m) / Density (D) - cm3 or m3</p>
            <p className="text-xs text-muted-foreground mt-2">Unit conversion: 1 g/cm3 = 1 kg/L = 1,000 kg/m3</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How the Density Formula Works in Physics</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Material", "Density (g/cm3)", "Density (kg/m3)", "Floats in Water?"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Air (sea level)", "0.0012", "1.2", "Yes (rises)"],
                  ["Wood (oak)", "0.60-0.90", "600-900", "Yes (floats)"],
                  ["Ice", "0.917", "917", "Yes (floats)"],
                  ["Water (4 C)", "1.000", "1,000", "Reference (1.0)"],
                  ["Seawater", "1.025", "1,025", "-"],
                  ["Aluminum", "2.70", "2,700", "No (sinks)"],
                  ["Iron / Steel", "7.87", "7,870", "No (sinks)"],
                  ["Copper", "8.96", "8,960", "No (sinks)"],
                  ["Lead", "11.34", "11,340", "No (sinks)"],
                  ["Gold", "19.32", "19,320", "No (sinks)"],
                  ["Osmium", "22.59", "22,590", "No (densest natural element)"],
                ].map(([mat, gcm, kgm, floats]) => (
                  <tr key={mat} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{mat}</td>
                    <td className="py-2.5 px-4 text-cyan-600 dark:text-cyan-400 font-medium">{gcm}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{kgm}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{floats}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Physics Density Tool for Students and Professionals</h2>
          <ul className="space-y-2 text-muted-foreground list-disc list-inside">
            <li><strong className="text-foreground">Buoyancy:</strong> An object floats if its average density is less than the fluid it's in. Ships float because their overall density (hull + air interior) is less than water despite being made of steel.</li>
            <li><strong className="text-foreground">Material identification:</strong> Unknown metals can often be identified by measuring their density with a scale and water displacement method, then comparing to known values.</li>
            <li><strong className="text-foreground">Aviation:</strong> Air density affects lift and engine performance. Aircraft must use density altitude (adjusted for temperature and pressure) rather than true altitude for performance calculations.</li>
            <li><strong className="text-foreground">Cooking:</strong> Dense liquids like cream sink below less-dense liquids like water. This creates layered cocktails and explains how oil floats on water in salad dressings.</li>
          </ul>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/density-calculator" headingLevel="h3" />
      </main>
    </>
  );
}



